<main>
  <div id="modal" class="{centered ? "c" : ""}" use:clickOutside on:click_outside={() => close()}>
    <div id="close" on:click={() => close()}></div>
    <slot></slot>
  </div>
</main>

<script>
  export let centered = false;
  import { clickOutside } from '../js/clickOutside.js';
  import { createEventDispatcher } from 'svelte';

	const dispatch = createEventDispatcher();

	function close() {
		dispatch('close');
	}
</script>

<style>
  #close {
    position: absolute;
    cursor: pointer;
    top: 25px;
    right: 25px;
    width: 32px;
    height: 32px;
    opacity: 0.3;
  }
  #close:hover {
    opacity: 1;
  }
  #close:before, #close:after {
    position: absolute;
    left: 15px;
    content: ' ';
    height: 33px;
    width: 2px;
    background-color: #333;
  }
  #close:before {
    transform: rotate(45deg);
  }
  #close:after {
    transform: rotate(-45deg);
  }
  .c {
    align-items: center;
    justify-content: center;
  }
  main {
    z-index: 100;
    cursor: pointer;
    position: absolute;
    top: 0px;
    left: 0px;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 100%;
    background-color: #0003;
  }
  #modal {
    position: relative;
    cursor: default;
    padding: 40px;
    min-width: 300px;
    min-height: 400px;
    background-color: white;
    border-radius: 20px;
    display: flex;
    flex-direction: column;
  }
</style>