//import MidiPlayer from 'midi-player-js';
import Soundfont from 'soundfont-player';

const AudioContext = window.AudioContext || window.webkitAudioContext || false; 
const ac = new AudioContext || new webkitAudioContext;

const font = 'https://raw.githubusercontent.com/gleitz/midi-js-soundfonts/gh-pages/MusyngKite/acoustic_guitar_nylon-mp3.js';
let Player;

export async function init() {
  Soundfont.instrument(ac, font)
  .then((instrument) => {
    Player = instrument;
    return 1;
  })
  .catch((e) => {
    return 0;
  });
}

export function play(n) {
  //console.log(n)
  Player.play(n);
}

export function start(f) {
  fetch('./midi/' + f)
    .then(response => response.blob())
    .then(blob => {
      const reader = new FileReader();
      reader.onload = function() {
        Player.loadDataUri(this.result);
        Player.play();
      }
      return reader.readAsDataURL(blob);
    })
    .catch((error) => {
      console.log(error)
    });
}