<main>
	<svg height="270" width="735">
		<line id="ledgerline" x1="0" y1="60" x2="735" y2="60" style="stroke:rgb(0,0,0);stroke-width:2" />
		{#each Array(4) as _, i}
			<use href="#ledgerline" y={(i + 1) * 30}/>
		{/each}
		<image x="10" y="12" width="130" height="230" href="graphics/clef.svg" />
		<defs>
			<image id="up" x="140" y="0" width="40" height="120" href="graphics/up.svg" />
			<image id="down" x="140" y="0" width="40" height="120" href="graphics/down.svg" />
			<line id="helpline" x1="0" y1="0" x2="52" y2="0" style="stroke:rgb(0,0,0);stroke-width:2" />
		</defs>
		{#each guess as n, i}
			{#if (n[0] > 13)}
				<use href="#helpline" x={(i * 60) + 134} y={(14 * 15)} />
			{/if}
			{#if (n[0] < 3)}
				<use href="#helpline" x={(i * 60) + 134} y={(2 * 15)} />
			{/if}
			{#if n[1] != -1}
				<image id="acc" x="{(i * 60) + 121}" y="{(n[0] * 15 - ((n[1] == 0) ? 40 : 27))}" height="55" href="graphics/accidentals/{n[1]}.svg" />
			{/if}
			<g in:appear style="transform-origin: center">
				{#if n[0] < 9}
					<use href="#down" style="" x="{(i * 60)}" y="{(n[0] * 15 - 15)}"/>
				{:else}
					<use href="#up" x="{(i * 60)}" y="{(n[0] * 15) - 105}"/>
				{/if}
			</g>
		{/each}
		{#if hover && enabled}
			<image id="acc" x="{(order * 60) + 121}" y="{(pos * 15 - ((accidental == 0) ? 40 : 27))}" height="55" href="graphics/accidentals/{accidental}.svg" />
			{#if (pos > 13)}
				<use href="#helpline" x={(order * 60) + 134} y={(14 * 15)} />
			{/if}
			{#if (pos < 3)}
				<use href="#helpline" x={(order * 60) + 134} y={(2 * 15)} />
			{/if}
			{#if pos < 9}
				<use href="#down" opacity="0.3" x={(order * 60)} y={(pos * 15 - 15)}/>
			{:else}
				<use href="#up" opacity="0.3" x={(order * 60)} y={(pos * 15) - 105}/>
			{/if}
		{/if}
	</svg>
	<div id="catch" on:mousedown={() => { mouseDown(true) }} on:touchend={() => { if (hover) { mouseDown(true) } }} on:touchmove={touchMove} on:mousemove={mouseMove} on:mouseleave={end}></div>
</main>

<script>
  import { bounceOut } from "svelte/easing";

	export let acc, results, ready, sound, sharedButton;
	import * as Midi from '../js/midi.js';
	const notes = ['B', 'A', 'G', 'F', 'E', 'D', 'C'];

	let playQueue = [];
	let isPlaying = false;
	
	let guess = [];
	let enabled = 1;

	let hover = false;
	let pos = 0;
	let order = 0;

	const appear = () => {
    return {
      css: (t) => {
        return `
        transform: rotateY(${(1-t)*90}deg);
        `;
      },
      easing: bounceOut,
      duration: 400,
    };
  };
	
	Midi.init();

	let accidental = 0;
	let ledgerAccidentals = new Array(20).fill(1);
	let soundEnabled = 1;
	
	acc.subscribe(value => {
		accidental = value;
	});

	sound.subscribe(value => {
		soundEnabled = value;
	});

	results.subscribe(value => {
		if (value.length) {
			let w = 0;
			for (let i = 0; i < value.length; i++) {
				if (value[i] != 2) {
					break;
				}
				w++;
			}

			if (w == 10) {
				enabled = false;
			}

			clear();
		}
	});

	export function clear() {
		ledgerAccidentals = new Array(20).fill(1);
		guess = [];
		hover = false;
		pos = 0;
		order = 0;
	}

	function touchMove(e) {
		if (order > 9) {
			hover = false; 
			return;
		}
		hover = true;
		let rect = e.target.getBoundingClientRect();
		let ycoord = e.targetTouches[0].pageY - rect.top;

		pos = Math.round((ycoord - 5) / 15);
		pos = Math.max(pos, 2);
		pos = Math.min(pos, 15)
		//console.log(pos)
	}

	function mouseMove(e) {
		if (order > 9) {
			hover = false; 
			return;
		}
		hover = true;
		pos = Math.round((e.offsetY - 5) / 15);
		pos = Math.max(pos, 2);
		pos = Math.min(pos, 15)
		//console.log(pos)
	}

	export function playAll() {
		if (!guess.length || isPlaying) return;

		sharedButton.set(1);

		guess.forEach(x => {
			playQueue.push([x[0], x[2]]);
		});

		isPlaying = setInterval(() => {
			play(...playQueue.shift());

			if (!playQueue.length) {
				clearInterval(isPlaying);
				isPlaying = false;
				sharedButton.set(0);
			}
		}, 400);
	}

	function play(pos, acc) {
		let note = pos - 1;
		let octave = 5;

		for (let _i = 0; _i < 2; _i++) {
			if (note >= notes.length) {
				note -= notes.length;
				octave--;
			}
		}

		note = notes[note] + (acc == 0 ? "b" : (acc == 2 ? "#" : "")) + octave;

		Midi.play(note);
	}

	export function mouseDown(sound, acc = accidental, position = pos) {
		if (order > 9 || !enabled) return;

		hover = 0;
		order += 1;
		let real = acc;

		if (ledgerAccidentals[position] != acc) {
			guess.push([position, acc, real]);
			ledgerAccidentals[position] = acc;
		} else {
			guess.push([position, -1, real]);
		}

		guess = guess; // update

		if (sound) {
			play(position, acc);
		}

		if (order > 2) {
			ready.set(guess);
		}
	}

	function end(e) {
		hover = false;
	}
</script>

<style>
	@media only screen and (max-width: 750px) {
		main {
			overflow: auto;
		}
		main::-webkit-scrollbar {
			min-width: 20px;
			min-height: 20px;
		}
	}
	div {
		-webkit-tap-highlight-color: rgba(0,0,0,0);
	}
	svg * {
		transform-box: fill-box;
	}
	main {
		position: relative;
	}
	#catch {
		width: 600px;
		height: 240px;
		position: absolute;
		top: 0px;
		left: 120px;
		cursor: pointer;
	}
</style>