<div id="par">
  <h1>How to play</h1>
  <p>Guess the fugue theme!</p>
  <p>You can guess any melody you'd like, granted that it's at least 3 notes long.</p>
  <p>After each guess, the color of the notes will change to show how close your guess was to the theme.</p>
  <hr>
  {#each example as ledger}
    <div id="example">
      <div id="wrap"><OldLedger size={0.4} width={500} guess={ledger.guess} legend={ledger.results}></OldLedger></div>
      <div id="exp">{@html ledger.text}</div>
    </div>
  {/each}
</div>

<script>
  import OldLedger from './OldLedger.svelte';
  const example = [
    {
      guess: [[14, -1, 1], [13, -1, 1], [12, -1, 1], [11, -1, 1], [10, -1, 1]],
      results: [3, 2, 3, 3, 3],
      text: "The note <b>D</b> is in the theme and in the correct spot."
    },
    {
      guess: [[13, 2, 2], [9, 2, 2], [8, -1, 1], [9, -1, 2], [10, 2, 2]],
      results: [3, 3, 3, 1, 3],
      text: "The note <b>A</b> is in the theme but in the wrong spot."
    },
    {
      guess: [[6, 2, 2], [5, -1, 1], [6, 1, 1], [5, -1, 1], [7, 2, 2]],
      results: [0, 3, 3, 3, 3],
      text: "The note <b>D#</b> is not in the theme in any spot."
    }
  ];
</script>

<style>
  h1 {
    padding: 0px;
    margin: 0px;
  }
  #par {
    height: 100%;
    width: 350px;
  }
  #example {
    padding-top: 10px;
  }
  #wrap {
    background-color: #f1f1f1;
    padding: 30px;
    display: flex;
    justify-content: center;
    border-radius: 20px;
  }
  #wrap :global(.small) {
    margin-top: -118px !important;
    margin-bottom: -128px !important;
  }
  #exp {
    margin-top: 10px;
  }
</style>