<main>
	<div id="wrapper">
		<div id="infobtn" on:click={() => { tutModal = 1; }}>?</div>
		<div id="lwrap" bind:this={ledgerList}>
			<div id="ledgers">
				{#each Guess as ledger}
					<OldLedger guess={ledger.guess} legend={ledger.results}></OldLedger>
				{/each}
			</div>
		</div>
		<div id="choose">
			<div id="trashwrap">
				<div on:mousedown={() => play()} class="button alt {playing ? "playing" : ""}" id="play"><img height="22px" src="graphics/{playing ? "play" : "play"}.svg"></div>
				<div on:mousedown={() => trash()} class="button alt" id="trash"><img height="22px" src="graphics/trash.svg"></div>
			</div>
			{#each Array(3) as _, i}
				<div on:mousedown={() => pick(i)} class="button alt c{i}" id="{(selected == i) ? "picked" : ""}"><img height="36px" src="graphics/accidentals/{i}.svg"></div>
			{/each}
			<div id="fillwrap">
				<div class="bigbtn button {(Guess.length && !won) ? "other-enabled" : "disabled"} btn" id="fill" on:click={() => fillIn()}>Fill in</div>
				<div class="bigbtn button {(Guess.length && hints && !hintUsed && !won) ? "other-enabled" : "disabled"} btn" id="hint" on:click={() => hint()}>Hint</div>
			</div>
		</div>
		<Ledger bind:playAll={ledgerPlay} bind:clear={ledgerClear} bind:mouseDown={ledgerInput} sharedButton={sharedButton} acc={current} results={results} ready={sharedReady} sound={soundEnabled}></Ledger>
		{#if won}
			<div class="button enabled btn playagain" id="guess" on:click={() => location.reload()}>Play again</div>
		{:else}
			<div class="button {ready ? "enabled" : "disabled"} btn" id="guess" on:click={() => guess()}>Guess</div>
		{/if}
	</div>
	{#if tutModal}
		<Modal on:close={() => { tutModal = 0; window.localStorage.setItem('tutorial', 0); }}>
			<Tutorial></Tutorial>
		</Modal>
	{/if}
	{#if winModal}
		<Modal centered={true} on:close={() => { winModal = 0; }}>
			<Win secret={secret}></Win>
		</Modal>
	{/if}
</main>

<script>
	import Modal from './components/Modal.svelte';
	import Win from './components/Win.svelte';
	import Tutorial from './components/Tutorial.svelte';
	import Ledger from './components/Ledger.svelte';
	import OldLedger from './components/OldLedger.svelte';

	import { writable } from 'svelte/store';
	import FugueList from './js/fugue.js';

	const current = writable(1);
	const results = writable([]);
	const sharedReady = writable([]);
	const soundEnabled = writable(1);
	const sharedButton = writable(0);

	let ledgerClear;
	let ledgerInput;
	let ledgerPlay;

	let ledgerList;

	let winModal = 0;
	let tutModal = 0;

	let tutorial = window.localStorage.getItem('tutorial');

	if (tutorial == null) {
		tutModal = 1;
	}

	let Guess = [];
	let won = 0;
	let playing = 0;
	let hints = 3;
	let hintUsed = 0;
	let selected = 0;
	let ready = 0;

	document.addEventListener('keydown', (event) => {
		switch (event.code) {
			case "Digit1":
				pick(0)
				break;
			case "Digit2":
				pick(1)
				break;
			case "Digit3":
				pick(2)
				break;
			default:
				break;
		}
	});

	let localCurrent = window.localStorage.getItem('current');

	if (localCurrent == null) {
		localCurrent = Math.round(Math.random() * (FugueList.length - 1));
		window.localStorage.setItem('current', localCurrent);
	}

	const secret = FugueList[Number(localCurrent)];
	
	current.subscribe(value => {
		selected = value;
	});

	sharedReady.subscribe(value => {
		if (value.length) {
			ready = value;
		}
	});

	sharedButton.subscribe(value => {
		playing = value;
	});

	function win() {
		won = 1;
		winModal = 1;
		let n = Math.round(Math.random() * (FugueList.length - 1));

		while(n == Number(localCurrent)) {
			n = Math.round(Math.random() * (FugueList.length - 1));
		}

		window.localStorage.setItem('current', n);
	}

	function play() {
		ledgerPlay();
	}

	function hint() {
		if (!hints || !Guess.length || hintUsed) return;
		hints--;
		hintUsed = true;

		const n = fillIn();
		let next = secret.notes[n];
		
		ledgerInput(0, next[2], next[0]);
	}

	function trash() {
		ready = 0;
		ledgerClear();
	}

	function pick(i) {
		current.set(i);
	}

	function cmp(x, y) {
		return (x[0] == y[0] && x[2] == y[2]);
	}

	function fillIn() {
		if (!Guess.length) return;
		ledgerClear();

		const g = Guess[Guess.length - 1];
		let n = [];

		for (let i = 0; i < g.results.length; i++) {
			if (g.results[i] == 2) {
				n.push(g.guess[i]);
			} else {
				break;
			}
		}

		n.forEach(x => {
			ledgerInput(0, x[2], x[0]);
		});

		return n.length;
	}

	function guess() {
		if (!ready) {
			alert("Please input the 5 first notes of the theme!");
			return;
		}

		//console.log(JSON.stringify(ready))

		hintUsed = false;

		let r = [];
		let c = 0;
		let copy = JSON.parse(JSON.stringify(secret.notes));

		for (let i = 0; i < ready.length; i++) {
			r[i] = 0;
			const e = ready[i];
			if (cmp(e, secret.notes[i])) {
				r[i] = 2;
				copy.splice((i - c), 1);
				c++;
			}
		}

		for (let i = 0; i < ready.length; i++) {
			const e = ready[i];
			if (r[i] == 2) continue;

			for (let j = 0; j < copy.length; j++) {
				if (cmp(e, copy[j])) {
					copy.splice(j, 1);
					r[i] = 1;
					break;
				}
			}
		}

		results.set(r);

		if (c == 10) {
			win();
		}

		setTimeout(() => {
			Guess.push({guess: ready, results: r});

			// RESET SHARED V.
			results.set([]);
			ready = 0;

			Guess = Guess;
			setTimeout(() => {
				ledgerList.scrollTop = ledgerList.scrollHeight;
			}, 2);
		}, 1);
	}
</script>

